import{_ as s,o as a,c as e,S as t}from"./chunks/framework.C6RQlTYc.js";const u=JSON.parse('{"title":"面试官问：Prompt Engineering 的核心原则是什么？Zero-shot、Few-shot、CoT 的区别？","description":"","frontmatter":{},"headers":[],"relativePath":"面试官问/17ai/q_ai_14-prompt_engineering.md","filePath":"面试官问/17ai/q_ai_14-prompt_engineering.md","lastUpdated":1778207238000}'),p={name:"面试官问/17ai/q_ai_14-prompt_engineering.md"};function i(r,n,o,l,c,h){return a(),e("div",null,[...n[0]||(n[0]=[t(`<h1 id="面试官问-prompt-engineering-的核心原则是什么-zero-shot、few-shot、cot-的区别" tabindex="-1">面试官问：Prompt Engineering 的核心原则是什么？Zero-shot、Few-shot、CoT 的区别？ <a class="header-anchor" href="#面试官问-prompt-engineering-的核心原则是什么-zero-shot、few-shot、cot-的区别" aria-label="Permalink to &quot;面试官问：Prompt Engineering 的核心原则是什么？Zero-shot、Few-shot、CoT 的区别？&quot;">​</a></h1><blockquote><p>📚 参考：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_22-prompt_engineering.html">Prompt Engineering</a> | <a href="/FE-prepare-interview/直击概念/17ai/s_ai_25-function_calling.html">Function Calling</a></p></blockquote><h2 id="_1-prompt-engineering-的核心原则是什么-zero-shot、few-shot、cot-的区别" tabindex="-1">1. Prompt Engineering 的核心原则是什么？Zero-shot、Few-shot、CoT 的区别？ <a class="header-anchor" href="#_1-prompt-engineering-的核心原则是什么-zero-shot、few-shot、cot-的区别" aria-label="Permalink to &quot;1. Prompt Engineering 的核心原则是什么？Zero-shot、Few-shot、CoT 的区别？&quot;">​</a></h2><p><strong>考察点</strong>：是否掌握 Prompt Engineering 的三大核心原则，能否区分 Zero-shot、Few-shot、CoT 的使用场景和写法。</p><details class="details custom-block"><summary>详细信息</summary><h2 id="核心回答" tabindex="-1">核心回答 <a class="header-anchor" href="#核心回答" aria-label="Permalink to &quot;核心回答&quot;">​</a></h2><p>Prompt Engineering 是设计和优化输入提示词以引导大模型产出期望结果的技巧。</p><p><strong>三大核心原则</strong>：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>1. 清晰性（Clarity）：明确告诉模型你要什么</span></span>
<span class="line"><span>   ❌ &quot;分析数据&quot;</span></span>
<span class="line"><span>   ✅ &quot;分析以下销售数据，找出同比增速 Top 3 的品类，用表格输出&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 上下文（Context）：提供足够的背景信息</span></span>
<span class="line"><span>   给定角色：&quot;你是一个资深前端面试官&quot;</span></span>
<span class="line"><span>   给定格式：指定输出 JSON Schema</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 约束（Constraints）：限定输出范围和格式</span></span>
<span class="line"><span>   &quot;用 50 字以内回答&quot; / &quot;只输出代码不要解释&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p><strong>提示策略对比</strong>：</p><table><thead><tr><th>策略</th><th>做法</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>Zero-shot</strong></td><td>不给示例，直接问</td><td>简单任务（翻译、摘要）</td></tr><tr><td><strong>Few-shot</strong></td><td>给 2-5 个输入→输出示例</td><td>格式敏感的生成任务</td></tr><tr><td><strong>Chain-of-Thought (CoT)</strong></td><td>加一句&quot;Let&#39;s think step by step&quot;</td><td>推理、数学、逻辑题</td></tr><tr><td><strong>System Prompt</strong></td><td>在 system role 中设定全局规则</td><td>对话系统的行为约束</td></tr></tbody></table><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>Few-shot 示例：</span></span>
<span class="line"><span>&quot;输入：今天天气真好 → 情绪：正面</span></span>
<span class="line"><span> 输入：今天被领导骂了 → 情绪：负面</span></span>
<span class="line"><span> 输入：一般般吧 → 情绪：中性</span></span>
<span class="line"><span> 输入：收到 offer 了！ → 情绪：&quot; → 模型会输出&quot;正面&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>CoT 示例：</span></span>
<span class="line"><span>问：&quot;小明有 5 个苹果，给了小红 2 个，又买了 3 个，还剩几个？&quot;</span></span>
<span class="line"><span>不加 CoT → 可能直接输出错误答案</span></span>
<span class="line"><span>加 CoT → &quot;让我们一步步思考：小明有 5 个 → 给小红 2 个后剩 3 个 → 又买了 3 个 → 5+3=8 个&quot; → 正确答案</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p><strong>前端实战建议</strong>：</p><ul><li>System Prompt 固定为前端角色（&quot;你是 XX 网站的智能助手&quot;）</li><li>关键提示词做成可配置模板</li><li>在 prompt 中要求输出结构化格式便于前端解析</li></ul><h2 id="面试回答要点" tabindex="-1">面试回答要点 <a class="header-anchor" href="#面试回答要点" aria-label="Permalink to &quot;面试回答要点&quot;">​</a></h2><ul><li>说出三大原则：清晰性、上下文、约束</li><li>区分 Zero-shot/Few-shot/CoT 的用法</li><li>知道 System Prompt 是持久化角色设定</li></ul></details><blockquote><p>来源：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_22-prompt_engineering.html">Prompt Engineering 概念讲解</a></p></blockquote>`,6)])])}const m=s(p,[["render",i]]);export{u as __pageData,m as default};
